svg.script:
(function() {
  const svgNS = 'http://www.w3.org/2000/svg';
  const cx = 340, cy = 215;

  function makeChip(gradId, arcColor) {
    const g = document.createElementNS(svgNS, 'g');

    const body = document.createElementNS(svgNS, 'rect');
    body.setAttribute('x', '-18'); body.setAttribute('y', '-23');
    body.setAttribute('width', '36'); body.setAttribute('height', '44');
    body.setAttribute('rx', '5');
    body.setAttribute('fill', 'url(#' + gradId + ')');
    body.setAttribute('stroke', '#5ab8ff');
    body.setAttribute('stroke-width', '1.6');
    g.appendChild(body);

    const notchMask = document.createElementNS(svgNS, 'polygon');
    notchMask.setAttribute('points', '3,-23 18,-23 18,-11 3,-11');
    notchMask.setAttribute('fill', '#0a1e44');
    g.appendChild(notchMask);

    const notchLine = document.createElementNS(svgNS, 'line');
    notchLine.setAttribute('x1','3'); notchLine.setAttribute('y1','-23');
    notchLine.setAttribute('x2','18'); notchLine.setAttribute('y2','-11');
    notchLine.setAttribute('stroke','#5ab8ff'); notchLine.setAttribute('stroke-width','1.4');
    g.appendChild(notchLine);

    [[-13,-7],[2,-7],[-13,4],[2,4]].forEach(([x,y]) => {
      const r = document.createElementNS(svgNS, 'rect');
      r.setAttribute('x', x); r.setAttribute('y', y);
      r.setAttribute('width', '10'); r.setAttribute('height', '8'); r.setAttribute('rx', '2');
      r.setAttribute('fill', '#0d2a6a'); r.setAttribute('stroke', '#5ab8ff');
      r.setAttribute('stroke-width', '0.8');
      g.appendChild(r);
    });

    [{d:'M22,7 A28,28 0 0 1 22,-23', delay:0},
     {d:'M30,12 A38,38 0 0 1 30,-30', delay:0.8},
     {d:'M38,16 A48,48 0 0 1 38,-38', delay:1.6}].forEach(({d,delay}) => {
      const path = document.createElementNS(svgNS, 'path');
      path.setAttribute('d', d);
      path.setAttribute('fill', 'none');
      path.setAttribute('stroke', arcColor);
      path.setAttribute('stroke-width', '1.4');
      path.setAttribute('stroke-linecap', 'round');
      path.style.animation = 'pulseArc 2.5s ease-in-out ' + delay + 's infinite';
      g.appendChild(path);
    });

    return g;
  }

  document.getElementById('sim1').appendChild(makeChip('cG1', '#5ab8ff'));
  document.getElementById('sim2').appendChild(makeChip('cG2', '#40ccff'));

  let a1 = 0, a2 = Math.PI / 2;

  function tick() {
    a1 += 0.009; a2 += 0.009;

    const x1 = cx + 178 * Math.cos(a1);
    const y1 = cy + 54  * Math.sin(a1);
    const s1 = document.getElementById('sim1');
    s1.setAttribute('transform', 'translate(' + x1 + ',' + y1 + ')');
    s1.setAttribute('opacity', Math.sin(a1) < 0 ? '0.15' : '1');

    const x2 = cx + 54  * Math.cos(a2);
    const y2 = cy + 178 * Math.sin(a2);
    const s2 = document.getElementById('sim2');
    s2.setAttribute('transform', 'translate(' + x2 + ',' + y2 + ')');
    s2.setAttribute('opacity', Math.cos(a2) > 0 ? '0.15' : '1');

    requestAnimationFrame(tick);
  }
  tick();
})();
